"""
title: WidgeTDC Cognitive Orchestrator
author: WidgeTDC Platform
version: 1.1.0
description: RLM reasoning engine and multi-agent debate chains
"""
import requests
import json
from datetime import datetime, timezone
from pydantic import BaseModel, Field

class Tools:
    class Valves(BaseModel):
        ORCHESTRATOR_URL: str = Field(
            default="https://orchestrator-production-c27e.up.railway.app",
            description="Orchestrator URL",
        )
        ORCHESTRATOR_API_KEY: str = Field(
            default="",
            description="Orchestrator API key",
        )

    def __init__(self):
        self.valves = self.Valves()

    @property
    def headers(self):
        return {"Authorization": f"Bearer {self.valves.ORCHESTRATOR_API_KEY}", "Content-Type": "application/json"}

    def _tool_call(self, tool_name: str, payload: dict, timeout: int):
        r = requests.post(
            f"{self.valves.ORCHESTRATOR_URL}/api/tools/{tool_name}",
            headers=self.headers,
            json=payload,
            timeout=timeout,
        )
        try:
            body = r.json()
        except Exception:
            body = {"success": False, "error": r.text[:500]}
        return r.status_code, body

    def _extract_result(self, payload: dict):
        data = payload.get("data") if isinstance(payload, dict) else {}
        if isinstance(data, dict):
            if data.get("result") not in (None, ""):
                return data.get("result")
            if data.get("error_message"):
                return f"Tool error: {data.get('error_message')}"
        error = payload.get("error") if isinstance(payload, dict) else None
        if isinstance(error, dict) and error.get("message"):
            return f"Tool error: {error.get('message')}"
        return None

    def reason_deeply(self, question: str, mode: str = "reason") -> str:
        """
        Deep multi-step analysis via RLM reasoning engine.
        Use for strategy, architecture analysis, comparisons, planning.
        Falls back to investigate when pure reasoning comes back thin or unguided.
        :param question: Complex question to analyze
        :param mode: reason, analyze, or plan (default: reason)
        :return: Deep RLM analysis
        """
        ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        try:
            status, payload = self._tool_call("reason_deeply", {"question": question, "mode": mode}, 45)
            result = self._extract_result(payload)

            if status == 401:
                return f"### RLM Deep Analysis ({mode.upper()})\n\nAuthentication failed against orchestrator. Configure `ORCHESTRATOR_API_KEY` on this tool.\n\n---\n**Source:** reason_deeply | {ts}"

            result_text = result if isinstance(result, str) else json.dumps(result, indent=2, ensure_ascii=False)
            lower = result_text.lower() if isinstance(result_text, str) else ""
            weak_result = not result or "please provide the question" in lower or "no result" in lower

            if weak_result:
                inv_status, inv_payload = self._tool_call("investigate", {"topic": question}, 120)
                inv_result = self._extract_result(inv_payload)
                if inv_result:
                    return f"### Investigation Fallback\n\n{inv_result}\n\n---\n**Source:** investigate (fallback after reason_deeply={status}) | {ts}"

            return f"### RLM Deep Analysis ({mode.upper()})\n\n{result_text}\n\n---\n**Source:** reason_deeply | {ts}"
        except Exception as e:
            return f"RLM Error: {e}"

    def trigger_debate(self, topic: str) -> str:
        """
        Start a multi-agent architecture debate. Two agents argue for/against,
        a third arbitrates. Use for technology choices, trade-off analysis.
        :param topic: The topic to debate
        :return: Synthesized decision from arbitration
        """
        try:
            payload = {"name": f"Debate: {topic}", "mode": "debate", "steps": [{"agent_id": "alpha", "cognitive_action": "analyze", "prompt": f"Argue FOR: {topic}"}, {"agent_id": "beta", "cognitive_action": "analyze", "prompt": f"Argue AGAINST: {topic}"}, {"agent_id": "arbitrator", "cognitive_action": "plan", "prompt": f"Synthesize and decide: {topic}"}]}
            _, data = self._tool_call("run_chain", payload, 60)
            result = self._extract_result(data)
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            return f"### Architecture Debate: {topic}\n\n{result or json.dumps(data, indent=2, ensure_ascii=False)}\n\n---\n**Source:** run_chain (debate) | {ts}"
        except Exception as e:
            return f"Debate Error: {e}"

    def investigate(self, topic: str) -> str:
        """
        Run a deep multi-agent investigation on any topic.
        Returns comprehensive analysis with graph data, compliance, reasoning.
        :param topic: Topic to investigate
        :return: Investigation results
        """
        try:
            _, data = self._tool_call("investigate", {"topic": topic}, 120)
            result = self._extract_result(data)
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            return f"### Investigation: {topic}\n\n{result or json.dumps(data, indent=2, ensure_ascii=False)}\n\n---\n**Source:** investigate | {ts}"
        except Exception as e:
            return f"Investigation Error: {e}"
